def binary_search(lst, target):
    l = 0
    r = len(lst) - 1
    while l <= r:
        m = (l + r) // 2
        if lst[m] == target:
            return m
        elif lst[m] < target:
            l = m + 1
        else:
            r = m - 1
    return -1
