    def get(self, k):
        if k not in self.m:
            return -1
        n = self.m[k]
        if n == self.tail:
            return n.v
        if n.p:
            n.p.n = n.n
        if n.n:
            n.n.p = n.p
        if n == self.head:
            self.head = n.n
        else:
            n.p = None
        n.n = None
        n.p = self.tail
        self.tail.n = n
        self.tail = n
        return n.v

    def put(self, k, v):
        if k in self.m:
            n = self.m[k]
            n.v = v
            self.get(k)
        else:
            if self.size >= self.cap:
                del self.m[self.head.k]
                self.head = self.head.n
                if self.head:
                    self.head.p = None
                self.size -= 1
            n = Node(k, v)
            self.m[k] = n
            if not self.head:
                self.head = n
                self.tail = n
            else:
                n.p = self.tail
                self.tail.n = n
                self.tail = n
            self.size += 1

