class EventEmitter:
    def __init__(self):
        self.e = {}

    def on(self, e, f):
        if e not in self.e:
            self.e[e] = []
        self.e[e].append(f)

    def off(self, e, f):
        if e in self.e:
            self.e[e].remove(f)

    def emit(self, e, *a):
        if e in self.e:
            for f in self.e[e]:
                f(*a)
