import json

def parse_json(s):
    i = 0
    def parse_value():
        if s[i] == '{':
            return parse_object()
        elif s[i] == '[':
            return parse_array()
        elif s[i] == '"' or s[i].isdigit() or s[i] == '-':
            return parse_string()
        else:
            return None

    def parse_object():
        o = {}
        i += 1
        while s[i] != '}' and i < len(s):
            k = parse_string()
            if k is None:
                return None
            i += 1
            if s[i] != ':':
                return None
            i += 1
            v = parse_value()
            if v is None:
                return None
            o[k] = v
            if i < len(s) and s[i] == ',':
                i += 1
        i += 1
        return o

    def parse_array():
        a = []
        i += 1
        while s[i] != ']' and i < len(s):
            v = parse_value()
            if v is None:
                return None
            a.append(v)
            if i < len(s) and s[i] == ',':
                i += 1
        i += 1
        return a

    def parse_string():
        i += 1
        start = i
        while i < len(s) and s[i] != '"':
            i += 1
        if i >= len(s) or s[i] != '"':
            return None
        i += 1
        return s[start:i]

    return parse_value()
